from flask import Flask, send_file, abort
import os

app = Flask(__name__)

@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    try:
        invoice_filename = f'invoice_{invoice_id}.pdf'
        invoices_dir = 'invoices/' # define the directory where the invoices are stored
        
        if os.path.exists(os.path.join(invoices_dir, invoice_filename)):
            return send_file(os.path.join(invoices_dir, invoice_filename), as_attachment=True)
        else:
            abort(404, description="Invoice not found")
    except Exception as e:
        return str(e)

if __name__ == '__main__':
    app.run()